#include<bits/stdc++.h>
using namespace std;
char s[22000010];
int p[22000010],l[22000010],r[22000010],cnt,ans;
int main()
{
    s[0]='~';
    s[cnt=1]='|';
    char ch=getchar();
    while(!isalpha(ch))
    {
        ch=getchar();
    }
    while(isalpha(ch))
    {
        s[++cnt]=ch;
        s[++cnt]='|';
        ch=getchar();
    }
    int R=0,mid=0;
    for(int i=1;i<=cnt;i++)
    {
        if(i<=R)
        {
            p[i]=min(p[mid*2-i],R-i+1);
        }
        while(s[i-p[i]]==s[i+p[i]])
        {
            p[i]++;
        }
        if(p[i]+i>R)
        {
            R=p[i]+i-1;
            mid=i;
        }
        l[i-p[i]+1]=max(l[i-p[i]+1],p[i]-1);
        r[i+p[i]-1]=max(r[i+p[i]-1],p[i]-1);
    }
    for(int i=cnt;i>=1;i-=2)
    {
        r[i]=max(r[i],r[i+2]-2);
    }
    for(int i=1;i<=cnt;i+=2)
    {
        l[i]=max(l[i],l[i-2]-2);
    }
    for(int i=1;i<=cnt;i+=2)
    {
        if(l[i]&&r[i])
        {
            ans=max(ans,l[i]+r[i]);
        }
    }
    printf("%d",ans);
    return 0;
}
